import{_ as t,o as r,c as s,a2 as i}from"./chunks/framework.2UjvPF9X.js";const m=JSON.parse(`{"title":"Checklist d'évitement des anti-patterns","description":"Checklist d'évitement des anti-patterns à vérifier lors de l'écriture de code RxJS. Couvre 16 meilleures pratiques incluant la désinscription appropriée des Subscriptions, l'utilisation correcte des Subjects, l'implémentation de la gestion d'erreurs, la prévention des fuites mémoire, et fournit les éléments essentiels pour réaliser du code réactif robuste et maintenable.","frontmatter":{"description":"Checklist d'évitement des anti-patterns à vérifier lors de l'écriture de code RxJS. Couvre 16 meilleures pratiques incluant la désinscription appropriée des Subscriptions, l'utilisation correcte des Subjects, l'implémentation de la gestion d'erreurs, la prévention des fuites mémoire, et fournit les éléments essentiels pour réaliser du code réactif robuste et maintenable."},"headers":[],"relativePath":"fr/guide/anti-patterns/checklist.md","filePath":"fr/guide/anti-patterns/checklist.md","lastUpdated":1765219888000}`),a={name:"fr/guide/anti-patterns/checklist.md"};function o(n,e,l,c,d,u){return r(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="checklist-d-evitement-des-anti-patterns" tabindex="-1">Checklist d&#39;évitement des anti-patterns <a class="header-anchor" href="#checklist-d-evitement-des-anti-patterns" aria-label="Permalink to &quot;Checklist d&#39;évitement des anti-patterns&quot;">​</a></h1><p>Utilisez cette checklist pour vérifier si votre code RxJS correspond à un anti-pattern. Cliquez sur chaque élément pour voir des explications détaillées et des exemples de code.</p><h2 id="points-de-verification" tabindex="-1">Points de vérification <a class="header-anchor" href="#points-de-verification" aria-label="Permalink to &quot;Points de vérification&quot;">​</a></h2><h3 id="🔴-eviter-les-problemes-critiques" tabindex="-1">🔴 Éviter les problèmes critiques <a class="header-anchor" href="#🔴-eviter-les-problemes-critiques" aria-label="Permalink to &quot;🔴 Éviter les problèmes critiques&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">Vérification</th><th>Élément</th><th>Points clés</th></tr></thead><tbody><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#1-subject-の外部公開">Exposer les Subjects avec asObservable()</a></strong></td><td>Ne pas exporter directement les <code>Subject</code>, les exposer comme Observable avec <code>asObservable()</code><br>Permettre les changements d&#39;état uniquement via des méthodes dédiées</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#2-ネストした-subscribe-コールバック地獄">Éviter les souscriptions imbriquées</a></strong></td><td>Ne pas appeler d&#39;autres <code>subscribe</code> dans un <code>subscribe</code><br>Aplatir avec <code>switchMap</code>, <code>mergeMap</code>, <code>concatMap</code>, etc.</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#3-unsubscribe-忘れ-メモリリーク">Toujours se désabonner des flux infinis</a></strong></td><td>Toujours se désabonner des flux infinis comme les écouteurs d&#39;événements<br>Pattern <code>takeUntil</code> ou gestion de <code>Subscription</code></td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#4-sharereplay-の誤用">Spécifier explicitement la configuration de shareReplay</a></strong></td><td>Utiliser le format <code>shareReplay({ bufferSize: 1, refCount: true })</code><br>Activer le comptage de références pour prévenir les fuites mémoire</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./subscribe-if-hell">Éviter les imbrications if dans subscribe</a></strong></td><td>Éviter les branchements conditionnels complexes dans <code>subscribe</code> (3+ imbrications)<br>Écrire de manière déclarative avec des opérateurs comme <code>filter</code>, <code>iif</code>, <code>partition</code></td></tr></tbody></table><h3 id="🟡-eviter-les-problemes-necessitant-attention" tabindex="-1">🟡 Éviter les problèmes nécessitant attention <a class="header-anchor" href="#🟡-eviter-les-problemes-necessitant-attention" aria-label="Permalink to &quot;🟡 Éviter les problèmes nécessitant attention&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">Vérification</th><th>Élément</th><th>Points clés</th></tr></thead><tbody><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#5-map-での副作用">map pour fonctions pures, tap pour effets de bord</a></strong></td><td>Ne pas modifier l&#39;état ou logger dans <code>map</code><br>Séparer explicitement les effets de bord avec l&#39;opérateur <code>tap</code></td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#6-cold-hot-observable-の違いの無視">Utiliser Cold/Hot de manière appropriée</a></strong></td><td>Convertir en Hot avec <code>shareReplay</code> pour les requêtes HTTP, etc.<br>Déterminer si doit être exécuté pour chaque souscription ou partagé</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#7-promise-と-observable-の不適切な混在">Convertir les Promises avec from</a></strong></td><td>Ne pas mélanger Promise et Observable<br>Convertir en Observable avec <code>from()</code> pour un traitement unifié</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#8-バックプレッシャーの無視">Contrôler les événements à haute fréquence</a></strong></td><td>Contrôler l&#39;entrée de recherche avec <code>debounceTime</code>, le défilement avec <code>throttleTime</code><br>Exclure les doublons avec <code>distinctUntilChanged</code></td></tr></tbody></table><h3 id="🔵-ameliorer-la-qualite-du-code" tabindex="-1">🔵 Améliorer la qualité du code <a class="header-anchor" href="#🔵-ameliorer-la-qualite-du-code" aria-label="Permalink to &quot;🔵 Améliorer la qualité du code&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">Vérification</th><th>Élément</th><th>Points clés</th></tr></thead><tbody><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#9-エラーの握りつぶし">Gérer correctement les erreurs</a></strong></td><td>Capturer les erreurs avec <code>catchError</code> et les gérer correctement<br>Afficher des messages d&#39;erreur compréhensibles pour l&#39;utilisateur<br>Réessayer avec <code>retry</code> / <code>retryWhen</code> si nécessaire</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#10-dom-イベントサブスクリプションのリーク">Libérer correctement les événements DOM</a></strong></td><td>Toujours se désabonner des souscriptions <code>fromEvent</code><br>Désinscription automatique avec <code>takeUntil</code> lors de la destruction du composant</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#11-型安全性の欠如-any-の多用">Assurer la sécurité de type</a></strong></td><td>Définir des interfaces ou des alias de types<br>Spécifier explicitement le paramètre de type de <code>Observable&lt;T&gt;</code><br>Utiliser l&#39;inférence de type de TypeScript</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#12-不適切なオペレーター選択">Sélectionner l&#39;opérateur approprié</a></strong></td><td>Recherche: <code>switchMap</code>, parallèle: <code>mergeMap</code><br>Séquentiel: <code>concatMap</code>, anti-spam: <code>exhaustMap</code></td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#13-過度な複雑化">RxJS non nécessaire pour traitements simples</a></strong></td><td>Le JavaScript normal suffit pour le traitement de tableaux, etc.<br>Utiliser RxJS pour le traitement asynchrone et les flux d&#39;événements</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#14-subscribe-内での状態変更">Gérer l&#39;état de manière réactive</a></strong></td><td>Gérer l&#39;état avec <code>BehaviorSubject</code> ou <code>scan</code><br>Utiliser <code>subscribe</code> comme déclencheur final</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td><strong><a href="./common-mistakes#15-テストの欠如">Écrire des tests</a></strong></td><td>Effectuer des tests marble avec <code>TestScheduler</code><br>Rendre le traitement asynchrone testable de manière synchrone</td></tr></tbody></table><h2 id="utilisation" tabindex="-1">Utilisation <a class="header-anchor" href="#utilisation" aria-label="Permalink to &quot;Utilisation&quot;">​</a></h2><h3 id="_1-lors-de-la-revue-de-code" tabindex="-1">1. Lors de la revue de code <a class="header-anchor" href="#_1-lors-de-la-revue-de-code" aria-label="Permalink to &quot;1. Lors de la revue de code&quot;">​</a></h3><p>Après avoir écrit du nouveau code, effectuez une auto-revue en utilisant cette checklist.</p><h3 id="_2-lors-de-la-pull-request" tabindex="-1">2. Lors de la pull request <a class="header-anchor" href="#_2-lors-de-la-pull-request" aria-label="Permalink to &quot;2. Lors de la pull request&quot;">​</a></h3><p>En incluant cette checklist dans le template de pull request, vous pouvez vérifier avec les reviewers selon des critères communs.</p><h3 id="_3-revue-reguliere" tabindex="-1">3. Revue régulière <a class="header-anchor" href="#_3-revue-reguliere" aria-label="Permalink to &quot;3. Revue régulière&quot;">​</a></h3><p>Utilisez régulièrement cette checklist sur la base de code existante pour vérifier qu&#39;aucun anti-pattern ne s&#39;est infiltré.</p><h3 id="_4-partage-au-sein-de-l-equipe" tabindex="-1">4. Partage au sein de l&#39;équipe <a class="header-anchor" href="#_4-partage-au-sein-de-l-equipe" aria-label="Permalink to &quot;4. Partage au sein de l&#39;équipe&quot;">​</a></h3><p>Partagez avec les membres de l&#39;équipe pour unifier les meilleures pratiques RxJS.</p><h2 id="ressources-connexes" tabindex="-1">Ressources connexes <a class="header-anchor" href="#ressources-connexes" aria-label="Permalink to &quot;Ressources connexes&quot;">​</a></h2><ul><li><strong><a href="./common-mistakes">Erreurs courantes et solutions</a></strong> - Explication détaillée de chaque anti-pattern et exemples de code</li><li><strong><a href="./index">Sommaire des anti-patterns</a></strong> - Liste des anti-patterns et progression de l&#39;apprentissage</li><li><strong><a href="/RxJS-with-TypeScript/fr/guide/error-handling/strategies">Gestion des erreurs</a></strong> - Meilleures pratiques de gestion d&#39;erreurs</li><li><strong><a href="/RxJS-with-TypeScript/fr/guide/testing/unit-tests">Méthodes de test</a></strong> - Comment tester le code RxJS</li></ul><h2 id="conseils-pour-utiliser-la-checklist" tabindex="-1">Conseils pour utiliser la checklist <a class="header-anchor" href="#conseils-pour-utiliser-la-checklist" aria-label="Permalink to &quot;Conseils pour utiliser la checklist&quot;">​</a></h2><ol><li><p><strong>Ne pas essayer de tout perfectionner en une fois</strong></p><ul><li>Traiter d&#39;abord prioritairement les problèmes critiques (🔴)</li><li>Améliorer progressivement</li></ul></li><li><p><strong>Décider des priorités au sein de l&#39;équipe</strong></p><ul><li>Ajuster l&#39;importance selon les caractéristiques du projet</li><li>Créer une checklist personnalisée</li></ul></li><li><p><strong>Considérer l&#39;automatisation</strong></p><ul><li>Vérification automatique avec des outils d&#39;analyse statique comme ESLint</li><li>Intégrer dans le pipeline CI/CD</li></ul></li><li><p><strong>Mettre à jour régulièrement</strong></p><ul><li>Mettre à jour selon les mises à niveau de version de RxJS</li><li>Refléter les connaissances acquises par l&#39;expérience de l&#39;équipe</li></ul></li></ol><hr><p><strong>Important</strong> : Cette checklist n&#39;est pas pour écrire du code parfait, mais un guide pour éviter les problèmes courants. Utilisez-la de manière flexible selon le contexte du projet.</p>',24)])])}const h=t(a,[["render",o]]);export{m as __pageData,h as default};
